var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지께서... 그런 짓을 할 리 없어.","JPN":"お父様が……そんなことをするはずがない。","ENG":"My father... would never do something like that.","TWN":"父親不可能做出那種事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"전부...!","JPN":"全部……！","ENG":"It must all...!","TWN":"這一切……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그자의 탓일 테니까...!","JPN":"全部あの者のせいなのだから……！","ENG":"Be that person's fault...!","TWN":"一定都是那傢伙的錯……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"대체 당신에게 누가 무슨 짓을 저지른 거야?","JPN":"いったいあなたに誰が、何をしたの？","ENG":"What exactly did someone do to you?","TWN":"到底是誰對你做了什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"누구보다 그 녀석을 막으려 했던 당신이... 왜 그렇게 변한 거냐고.","JPN":"誰よりもあいつを止めようとしていたあなたが……どうしてそんな風になっちゃったんだよ。","ENG":"You of all people, who tried harder than anyone to stop that person... why did you change like that?","TWN":"比起任何人都更想阻止那傢伙的你……為什麼變成這樣了？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"제 마음은, 한 번도 변한 적 없사옵니다.","JPN":"わたくしの心は、一度も変わっておりません。","ENG":"My heart has never changed, not even once.","TWN":"我的心，未曾改變。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저는... 어제와 같은 오늘이 좋사옵니다.","JPN":"わたくしは……昨日と同じ今日が良いのでございます。","ENG":"I... prefer a today that is the same as yesterday.","TWN":"我……喜歡像昨天一樣的今天。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저의 과거가 타인에 대한 증오를 품는다면, 오늘 역시 과거의 증오에 물들여 질 테지요. ","JPN":"過去のわたくしが他人に対して憎悪を抱いていたら、今日のわたくしもまた過去の憎悪に染まるでしょう。 ","ENG":"If my past harbors hatred toward others, then today too will be stained by that hatred of the past.","TWN":"如果我的過去對他人抱有仇恨，那麼今天也會被過去的仇恨染上色彩。 "},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그런 끝없는 굴레에 갇히는 걸... 저는 원치 않나이다.","JPN":"そのような繰り返される運命に縛られることを……わたくしは望んでおりません。","ENG":"To be trapped in such an endless cycle... that is something I do not desire.","TWN":"我並不希望……被困在那樣無止盡的循環裡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...증오...","JPN":"……憎悪……","ENG":"...Hatred...","TWN":"……仇恨……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND"},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"나도... 다르지 않구나.","JPN":"自分も……同じだったんだ。","ENG":"I'm no different... am I?","TWN":"我也……一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다른 세계를 멸망시켜서... 그걸 양분으로 삼았다고?","JPN":"他の世界を滅亡させて……それを養分にしてるだって？","ENG":"You're saying another world was destroyed... and used as nourishment?","TWN":"毀滅其他世界……再把那一切當作養分？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예.","JPN":"はい。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그것이 제가 알게 된... 황금나무와 낙원의 진실이옵니다.","JPN":"これがわたくしが知り得た……黄金の木と楽園の真実でございます。","ENG":"That is the truth I came to learn... about the Golden Tree and the Promised Land.","TWN":"那正是我知道的……黃金樹與樂園的真相。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래서 넌 그 책임을 묻기 위해 아우드라를 만나려 했지만...","JPN":"それで、君はその責任を問うためにアウドラに会おうとしたけど……","ENG":"So you tried to meet Audra to hold her accountable...","TWN":"所以你原本打算去見奧德拉，向她追問這件事的責任……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"도중에 생각을 바꿔 날 찾아왔다는 거지?","JPN":"途中で気が変わって私のところに来たんだ。","ENG":"But you changed your mind along the way and came to see me instead?","TWN":"但途中改變想法、轉而來找我，是這樣嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...그렇사옵니다.","JPN":"……そうでございます。","ENG":"...That is correct.","TWN":"……就是這樣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"고마워. 날 믿기로 해줘서.","JPN":"ありがとう。私のことを信じてくれて。","ENG":"Thank you. For choosing to trust me.","TWN":"謝謝你，願意選擇相信我。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"전... 누군가를 믿으려는 게 아니옵니다.","JPN":"わたくしは……誰かを信じようとしているわけではございません。","ENG":"I... am not trying to trust someone.","TWN":"我……並不是想要相信誰。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저 스스로를 믿지 못하게 됐을 뿐.","JPN":"自分自身を信じられなくなっただけです。","ENG":"I simply came to a point where I could no longer trust myself.","TWN":"我只是連我自己都已經無法再相信了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 건 나도 마찬가지야.","JPN":"そんなの、私も同じだよ。","ENG":"I'm the same way.","TWN":"這一點我也一樣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"스스로를 믿을 순 없기 때문에, 다른 사람을 찾는 거지.","JPN":"自分自身を信用できないこそ、他の人に頼る。","ENG":"Because we can't trust ourselves, we end up looking for someone else.","TWN":"正因為無法相信自己，才會尋找別人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내면의 목소리라는 건 결국... 옳고 그름 앞에서 나 자신을 변호할 수 밖에 없으니까.","JPN":"内面の声というものは結局……良し悪しの前では自分自身を弁護してしまうものだからね。","ENG":"After all, the voice inside our heads can only end up defending ourselves when faced with right and wrong.","TWN":"所謂內心的聲音，到最後……在直面對與錯時，也只會替自己辯護罷了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러니 에클레시아도 날 도와줘.","JPN":"だから、エクレシアも私を助けて。","ENG":"So help me too, Ecclesia.","TWN":"所以艾可露西亞，也請你幫幫我。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 잘못된 길에 들어서 일을 그르치지 않도록.","JPN":"私が間違った道を選んで、失敗しないように。","ENG":"So that I don't lose my way and make a mistake.","TWN":"別讓我走上錯誤的道路，把事情搞砸。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...이제, 어쩌할 계획이시옵니까?","JPN":"……これから、どうするおつもりですか？","ENG":"...What do you plan to do now?","TWN":"……那麼，你接下來打算怎麼做？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아침이 돌아오기 전, 아우드라는 분명 눈을 떴어.","JPN":"朝が来る前、アウドラは確かに目を覚ました。","ENG":"Before morning returned, Audra surely woke up.","TWN":"在早晨到來前，奧德拉應該已經醒了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그녀가 살아있다는 걸 확인했으니 만나러 가야지.","JPN":"彼女が生きてることを確認したから、会いに行く。","ENG":"Now that we know she's alive, we should go meet her.","TWN":"既然已經確認她還活著，就去見她吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇다면, 무기를 챙겨가는 게 좋겠사옵니다.","JPN":"なら、武器を用意された方が良いでしょう。","ENG":"In that case, it would be wise to bring weapons.","TWN":"這樣的話，最好還是帶上武器。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"무기? 싸우려고?","JPN":"武器？　戦う気？","ENG":"Weapons? You're expecting a fight?","TWN":"武器？要戰鬥嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"처음 만났을 땐 딱히 적의는 없어 보였는데.","JPN":"最初に出会った時には、特に敵意はなさそうだったけど。","ENG":"When we first met, she didn't seem to have any hostility.","TWN":"第一次見面時，她看起來不像有敵意。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그 검을 든 자가 나타나, 아우드라를 또 해칠지도 모르옵니다.","JPN":"あの剣を持った者が現れ、またアウドラを殺すかもしれません。","ENG":"The one who wielded that sword might appear again and harm Audra.","TWN":"也許會有拿著那把劍的人出現，再次傷害奧德拉。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아... 그 여자 말이지.","JPN":"あ……あの女ね。","ENG":"Ah... that woman.","TWN":"啊……你是說那個女人啊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"음- 우리한테 무기가 있어도 맞서기 힘들지 않을까? 엄청 강해 보이던데.","JPN":"うーん、私たちに武器があっても立ち向かうのは無理じゃないかな？　すごく強そうだったし。","ENG":"Hmm... Even if we had weapons, I doubt we could stand against her. She looked incredibly strong.","TWN":"嗯—就算我們有武器，也不一定打得過她吧？她看起來很厲害。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"막을 것이옵니다! 이쪽은 둘이지 않사옵니까!","JPN":"止めます！　こちらは二人ではございませんか！","ENG":"We will stop her! There are two of us, aren't there?","TWN":"我們一定能擋下！我們這邊是有兩個人不是嗎！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"으응... 네가 그렇게까지 말한다면야.","JPN":"う～ん……君がそこまで言うなら。","ENG":"Mm... If you insist that strongly.","TWN":"嗯……既然你都這麼說了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런데, 무기를 어디서 구하지?","JPN":"でも、どこから武器を持ってくるの？","ENG":"But where would we get weapons?","TWN":"不過，要去哪裡找武器？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"나 알아.","JPN":"私、知ってる。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L1_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"강한 무기 있는 곳.","JPN":"強い武器がある場所。","ENG":"A place with strong weapons.","TWN":"放置很厲害武器的地方。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"클라라...? 네가 무기를?","JPN":"クララ……？　君が武器を？","ENG":"Clara...? You know about weapons?","TWN":"克拉拉……？你知道武器在哪？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이 안에 무기가 있다고?","JPN":"この中に武器があるの？","ENG":"There are weapons inside this?","TWN":"你說這裡面有武器？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응, 어른들이 친구를 강해지게 하려고 많이 넣어뒀어요.","JPN":"うん、大人たちが友だちを強くするためにいっぱい入れてた。","ENG":"Yes. The adults put many inside my friend to make it stronger.","TWN":"嗯。大人為了讓朋友變強，裡面放了很多在裡面。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우리가 무기가 필요하다고는 했지만...","JPN":"武器が必要とは言ったけど……","ENG":"We did say we needed weapons, but...","TWN":"雖然我們需要武器……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네 친구는 잠들어있는데, 멋대로 꺼내도 괜찮을까?","JPN":"君の友だちは寝てるのに、勝手に持ち出しちゃっていいのかな？","ENG":"Your friend is sleeping. Is it really okay to take them out without asking?","TWN":"但你朋友現在在睡覺，我們這樣隨便拿出來真的沒問題嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"괜찮아.","JPN":"大丈夫。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"친구 여깄는 거 한 번도 안 썼어. 어른들이 실험하려고 꺼낼 때마다 간지러워서 싫댔거든요.","JPN":"友だちはここにあるの一度も使ってない。大人たちが実験しようとして取り出すたびに、くすぐったくて嫌だったって。","ENG":"My friend has never used the ones stored here. It said it tickled whenever the adults tried to take them out for experiments, so it didn't like it.","TWN":"這裡的東西我朋友一次都沒用過。每次大人要拿出來做實驗的時候，她都說很癢、不喜歡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그래서 제일로 센 거 하나만 있으면 된대.","JPN":"だから、一番強いのが一つだけあれば十分だって。","ENG":"So it said just one really strong one is enough.","TWN":"所以我們只要拿一個最強的就好了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"손잡이 같은 건 안 보이는데, 강제로라도 열어야 하나?","JPN":"取っ手は見当たらないけど、こじ開けないとだめかな？","ENG":"I don't see anything like a handle. Should we force it open?","TWN":"看不到像是把手的地方，要不要強行打開？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그건... 친구 분께 실례되는 짓이 아니올지.","JPN":"それは……ご友人に失礼かと存じます。","ENG":"That... would be rather rude to your friend, wouldn't it?","TWN":"那樣的話……似乎對你朋友有些失禮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼 다른 좋은 방법 있어?","JPN":"じゃあ、他にいい方法ある？","ENG":"Then do you have a better idea?","TWN":"那還有什麼好辦法嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그건, 그러니까...","JPN":"それは、その……","ENG":"Well, um...","TWN":"嗯，那樣的話……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저기, 클라라 님의 무쇠 친구 님!","JPN":"あの、クララ様の鋼鉄のご友人！","ENG":"Excuse me, Ms. Clara's steel friend!","TWN":"那個，克拉拉小姐的機器朋友！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"우리에겐 그대의 무기가 필요하옵니다. 부디 빌려주지 않으시렵니까?","JPN":"わたくしたちにはあなたの武器が必要なのです。どうかお貸しいただけないでしょうか？","ENG":"We are in need of your weapons. Would you be so kind as to lend us some?","TWN":"我們需要你的武器，可以請你借給我們一些嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"침묵하는 것으로 보아, 거절당한 듯하옵니다.","JPN":"沈黙しているところを見るに、拒絶されたのかと。","ENG":"Judging by the silence, I believe we've been refused.","TWN":"對方保持沉默，看來是拒絕了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그으래? 어쩔 수 없지.","JPN":"そ～お？　仕方ないね。","ENG":"Is that so? Well, it can't be helped.","TWN":"是嗎？那也沒辦法了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네퀴티아가 기억하는 그 에클레시아와 같은 인물이란 게 믿기지 않네.","JPN":"ネキティアの記憶するあのエクレシアと同じ人物ってのが信じられない。","ENG":"I can't believe this girl is the same Ecclesia that Nequitia remembers.","TWN":"真難相信，指揮家記憶裡的艾可露西亞就是你這樣的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래도... 저런 올곧고 답답한 점은 묘하게 닮았다고 해야하나?","JPN":"でも……ああいう真っ直ぐで堅苦しいところは妙に似てるっていうか。","ENG":"Still... that stubbornly upright nature of hers is strangely similar, isn't it?","TWN":"不過……這種正直到有點死腦筋的地方，倒是挺像的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"열려라- 뚜껑-","JPN":"開け～フタ～","ENG":"Lid... Open–","TWN":"打開吧—蓋子—"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"꺄앗-?!","JPN":"きゃあっ！？","ENG":"Kyaah?!","TWN":"吱啊—？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START2"},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"오, 열렸다.","JPN":"お、開いたね。","ENG":"Oh, it opened.","TWN":"哦，打開了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"클라라 님? 어떻게 한 것인지...?","JPN":"クララ様？　いったいどうやって……？","ENG":"Ms. Clara? How did you manage that...?","TWN":"克拉拉小姐？你怎麼做到的……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"문을 여는 주문. 까먹고 있다가 방금 떠올랐어.","JPN":"扉を開く呪文。忘れてたけど、今思い出した。","ENG":"It's a spell for opening doors. I forgot about it, but I just remembered.","TWN":"我剛剛才想起來打開門的咒語。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"주문...!","JPN":"呪文……！","ENG":"A spell...!","TWN":"咒語……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"무슨 SF영화에 나올 것 법한 총들이 잔뜩 있네.","JPN":"なんだかSF映画に出てきそうな銃がたくさんあるね。","ENG":"There's a ton of guns here that look like they came straight out of some sci-fi movie.","TWN":"裡面全是像科幻電影裡才會出現的槍。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_13"},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이게 방아쇠고... 이쪽이 카트리지를 꽂는 부분인가?","JPN":"これが引き金で……こっちがカートリッジをはめるところかな？","ENG":"This must be the trigger... and this part is where the cartridge goes, I think?","TWN":"這個是扳機……這邊是裝彈匣的地方嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"레아 님은... 어려운 말을 잔뜩 아시는 것 같사옵니다.","JPN":"レア様は……難しい言葉をたくさんご存じなのですね。","ENG":"Ms. Leah... you seem to know many complicated terms.","TWN":"蕾亞小姐……好像懂很多困難的東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이런 걸 전에 다룬 적 있으시옵니까?","JPN":"前にもこのようなものを扱っていた経験がおありなのですか？","ENG":"Have you used something like this before?","TWN":"你以前有用過這種武器嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나도 이런 건 처음 봐. 내가 아는 무기 지식으로 적당히 짜 맞춰 보는 거지.","JPN":"私もこんなのは初めてだよ。私の知ってる武器の知識で適当にやってみてるだけ。","ENG":"This is my first time seeing one too. I'm just piecing it together from what little I know about weapons.","TWN":"我也是第一次見到。只是利用我知道的武器知識，大概猜測而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...레아 님!","JPN":"……レア様！","ENG":"...Ms. Leah!","TWN":"……蕾亞小姐！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"으, 응?","JPN":"う、うん？","ENG":"Y-yes?","TWN":"嗯、嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저에게도 부디, 그 가르침을 나누어주옵소서!","JPN":"わたくしにもどうか、その知識を教えてくださいませ！","ENG":"Please, share that knowledge with me as well!","TWN":"也請務必教我那些知識！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"가르침이라...","JPN":"教えるって……","ENG":"Knowledge...?","TWN":"教你啊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 누굴 가르칠 처지가 아니긴 한데-","JPN":"私が誰かを教えられる立場ではないけど……","ENG":"I'm hardly in any position to teach someone...","TWN":"其實我的程度也不能教人—"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래도 총구를 자기 얼굴에 대고 있는 너보단 낫겠지.","JPN":"少なくとも銃口を自分の顔に当ててる君よりはマシかもね。","ENG":"But at least I'm better than someone pointing the muzzle at their own face.","TWN":"不過至少比你現在把槍口對著自己的臉好一點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"앗.","JPN":"あっ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이 카트리지는 일회용으로 만들어진 것 같아. 한 번 쓰면 새 걸로 갈아 끼워야 한다는 뜻이지.","JPN":"このカートリッジは使い捨てみたいだね。一度使ったら新しいものと交換しないといけないよ。","ENG":"This cartridge looks like it's made for one-time use. Once you fire it, you have to replace it with a new one.","TWN":"這個彈匣看起來是拋棄式的。用完就得換新的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고 총구는 자신과 반대 방향으로 향하게 하는 거야.","JPN":"そして銃口は自分の反対側に向ける。","ENG":"And always keep the muzzle pointed away from yourself.","TWN":"還有，槍口要朝著與自己相反的方向。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아하, 쥐는 법이 대롱과 비슷해보입니다.","JPN":"なるほど、握り方が竹筒と似ています。","ENG":"Ah, I see. The way you hold it resembles a blowpipe.","TWN":"原來如此，握法看起來和弩弓很像。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"차이점이 있다면 여기서 나가는 건 화살처럼 낙차가 크지 않다는 거야.","JPN":"違うのは、ここから出るものは矢のように落差が大きくないってこと。","ENG":"The difference is that what comes out of this doesn't drop like an arrow.","TWN":"差別在於從這裡射出的東西，不像箭那樣有明顯的下墜。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러니 표적을 겨눌 땐 똑바로 향하면 돼.","JPN":"だからターゲットを定める時には、真っ直ぐ向ければいい。","ENG":"So when you aim at a target, just point it straight.","TWN":"所以瞄準目標的時候，只要筆直對準就好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"표적을 조준했다면, 마지막으로-","JPN":"ターゲットを定めたら、最後に……","ENG":"Once you've lined up your target, the last step is...","TWN":"當你瞄準好目標後，最後—"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_28"},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...이 방아쇠를 손가락으로 당겨.","JPN":"……この引き金を指で引く。","ENG":"...Pull this trigger with your finger.","TWN":"……用手指扣下這個扳機。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_COFFIN_LASER_MAIN"},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"와앗, 깜짝아! 뭐야!","JPN":"わわっ、ビックリした！　何だ！","ENG":"Whoa! That startled me! What was that?!","TWN":"哇啊！嚇我一跳！怎麼了？！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여과기의 유압실린더가 처음 작동하는 소리에요.","JPN":"ろ過機の油圧シリンダーが初めて作動する音です。","ENG":"That's the sound of the filter's hydraulic cylinder activating for the first time.","TWN":"那是過濾器的液壓汽缸第一次啟動的聲音。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 말은 즉, 우물에 여과기가 제대로 연결됐다는 뜻이죠.","JPN":"つまり、イドにろ過機が正しく繋がったということを意味します。","ENG":"Which means the filter has successfully connected to the Well.","TWN":"也就是說過濾器已經順利接到井裡了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐가 잘못 돼서 터진 줄 알았다, 요녀석아.","JPN":"何か間違って爆発したのかと思ったよ。","ENG":"I thought something had gone wrong and exploded, you little rascal.","TWN":"我還以為哪裡出問題爆炸了呢，你這小鬼。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"도약 좌표 설정은 마쳤네.","JPN":"跳躍の座標設定は終わった。","ENG":"The jump coordinates are set.","TWN":"躍遷座標已經設定好了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼, 이제 남은 건 클리파와 여과기를 연결하는 것만 남았군.","JPN":"じゃあ、あとはクリファとろ過機を繋ぐだけか。","ENG":"Then all that remains is to connect Qlipha and the filter.","TWN":"那麼現在只剩下連結逆卡巴拉和過濾器了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말, 이걸 타고 내려가면 타기리온이 있는 곳으로 가게 되는 건가?","JPN":"本当にこれに乗って下りれば、タギリオンのところに行けるのか？","ENG":"If we ride this down, will it really take us to where Thagirion is?","TWN":"真的只要從這裡下去，就能到達塔基里翁所在之處嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"본인도 그것이 한 번에 가능하면 좋겠네만...","JPN":"それが一気にできたら良かったのだが……","ENG":"I would certainly prefer if it were that simple...","TWN":"如果能一次成功，當然再好不過……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대들은 우선 짧은 거리의 과거로 가게 될 거요.","JPN":"そなたらはまず、短い距離の過去に向かうことになるであろう。","ENG":"You will first travel a relatively short distance back to the past.","TWN":"但你們會先前往比較近的過去。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"짧다는 건 상대적일 뿐, 족히 20년은 되는 세월을 거스르게 될 게다.","JPN":"短いっていうのは相対的にそうだってだけで、ゆうに20年は遡ることになるよ。","ENG":"\\"Short\\" is relative. You'll be going back nearly twenty years.","TWN":"也只是相對來說比較近，你們至少要逆行20年的時間。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"20년...?","JPN":"20年……？","ENG":"Twenty years...?","TWN":"20年……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"고작 20년을 돌아가서 뭘 어쩌려고?","JPN":"たった20年遡ったところでどうしろと？","ENG":"What are we supposed to accomplish by going back only twenty years?","TWN":"只回到20年前，能做什麼？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"모름지기 큰 도약을 위해선 작은 도움닫기가 필요한 법이지.","JPN":"大きく跳躍するためには、小さな助走が必要なもの。","ENG":"A great leap always requires a small running start.","TWN":"要完成大躍遷，總得需要一段助跑。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"무한대에 가까운 시간을 거스르려면 과거와 현재에 두 개의 큰 우물을 연결해야 한다.","JPN":"無限大にも近い時間を遡るには、過去と現在の両方に大きなイドを繋げなければならない。","ENG":"To rewind time close to infinity, we must connect two Great Wells between the past and the present.","TWN":"想逆行接近無限的時間，就必須連接過去與現在兩口巨井。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"보다 큰 시공간 곡률을 열기 위해, 작은 목을 먼저 확보하는 과정이야.","JPN":"より大きな時空間の曲率を開くために、まずは小さな要所を確保する過程なんだよ。","ENG":"It's the process of securing a smaller node first, to open a larger spacetime curvature.","TWN":"為了打開更大的時空曲率，必須先確保一個較小的通道。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"과거에 이만한 우물을 하나 더 만들겠다고?","JPN":"過去にこの規模のイドをもう一つ作ろうというのか？","ENG":"You're saying we're going to create another Well of this scale in the past?","TWN":"你是說，要在過去再建一個這麼大的井？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그러려면 지금 계획보다 일꾼을 더 많이 데려가야 할 것 같은데...","JPN":"それだと、今の計画よりも作業者を多く連れて行かなくてはならなくなりそうだが……","ENG":"If that's the case, we'll probably need to bring more workers than the current plan calls for...","TWN":"那樣的話，恐怕得帶更多工人一起過去。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그 많은 일꾼들에게 채워줄 만큼 동앗줄의 여분이 넉넉친 않아.","JPN":"それほどの数の作業者に繋げられるほど、縄の数に余裕がない。","ENG":"We don't have enough spare Straw Rope to supply that many workers.","TWN":"可我們手上的繩索餘量，沒多到能供那麼多人使用。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래서 우리가 내린 결론은 이거다...!","JPN":"そこで私たちが出した結論がこれだ……！","ENG":"So the conclusion we reached is this...!","TWN":"所以我們得出的結論是……！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"과거로 가는 김에 그 시간대의 기술자들에게 손을 빌리는 것이지!","JPN":"過去に行くついでに、その時間帯の技術者たちに協力してもらう！","ENG":"Since we're going to the past anyway, we'll borrow the help of engineers from that era!","TWN":"既然都要去過去，乾脆找那個時代的技術人員幫忙。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"시간여행에서 과거 사람을 만나는 건 금기 아니었나?","JPN":"時間旅行で過去の人に会うのは禁忌ではなかったのか？","ENG":"Isn't meeting people from the past supposed to be forbidden in time travel?","TWN":"時間旅行不是禁止和過去的人接觸嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 그런 설정을 취급하는 작품도 있긴 하다만- 실제론 별 문제 없어.","JPN":"ま、そんな設定になってる作品もあるけど～実際は特に問題ない。","ENG":"Well, some stories treat it that way, but in reality it's not much of a problem.","TWN":"嗯，雖然有作品會這樣設定啦—但實際上並沒有問題。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"우리가 과거에 끼치는 행동은 우물길을 통해 잠시 연결된 동안에만 유효하고, 터널이 닫히는 순간 모든 게 원래대로 돌아가거든.","JPN":"私たちが過去に影響を及ぼす行動はイドの道を通じて繋がれている間だけ有効で、トンネルが閉じる瞬間にはすべてが元通りになるからね。","ENG":"Anything we do in the past only remains valid while the Well-path is temporarily connected, and the moment the tunnel closes, everything returns to normal.","TWN":"我們在過去造成的行動，只會在井道連接的那段時間有效。隧道一關閉，一切就會回到原本的狀態。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리가 돌아오기 전에 그 우물길이 닫히면 어떻게 되지?","JPN":"私たちが戻る前にそのイドの道が閉ざされたらどうなる？","ENG":"What happens if that Well-path closes before we come back?","TWN":"如果井道在我們回來之前就關閉了呢？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"햐, 영특한 학자답게 바로 맹점을 찌르는구먼.","JPN":"おお、頭のいい学者らしく、すぐに盲点を突いてくるな。","ENG":"Wow, just like a clever scholar to immediately spot the flaw.","TWN":"呵，果然是聰明的學者，一下就抓到盲點。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그렇게 되면 임무는 실패하고 지금까지 준비한 것들이 수포로 돌아간다는 것만 대-충 알아두거라.","JPN":"そうなったら任務は失敗、今まで準備してきたものが水泡に帰するってことだけざっくりと覚えておいて。","ENG":"If that happens, the mission fails and everything we prepared up to now goes to waste. That's all you need to roughly understand.","TWN":"那樣的話，就算任務失敗。到目前為止準備的一切，全都化為泡影。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"알아들었어. 대충은.","JPN":"分かった。ざっくりとね。","ENG":"I understand. Roughly.","TWN":"我大概聽懂了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};